import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st=new StringTokenizer(br.readLine());
        int T=Integer.parseInt(st.nextToken());
        StringBuilder out=new StringBuilder();
        while(T-- > 0){
            st=new StringTokenizer(br.readLine());
            int N=Integer.parseInt(st.nextToken());
            int M=Integer.parseInt(st.nextToken());
            long[] a=new long[N];
            long[] b=new long[M];
            st=new StringTokenizer(br.readLine());
            for(int i=0;i<N;i++) a[i]=Long.parseLong(st.nextToken());
            st=new StringTokenizer(br.readLine());
            for(int i=0;i<M;i++) b[i]=Long.parseLong(st.nextToken());
            int i=0,j=0; long last=Long.MIN_VALUE;
            StringBuilder line=new StringBuilder();
            while(i<N && j<M){
                if(a[i]<b[j]){ if(a[i]!=last){ line.append(a[i]).append(' '); last=a[i]; } i++; }
                else if(a[i]>b[j]){ if(b[j]!=last){ line.append(b[j]).append(' '); last=b[j]; } j++; }
                else{ if(a[i]!=last){ line.append(a[i]).append(' '); last=a[i]; } i++; j++; }
            }
            while(i<N){ if(a[i]!=last){ line.append(a[i]).append(' '); last=a[i]; } i++; }
            while(j<M){ if(b[j]!=last){ line.append(b[j]).append(' '); last=b[j]; } j++; }
            out.append(line.toString().trim()).append('\n');
        }
        System.out.print(out.toString());
    }
}

