import sys

def solve():
    data=sys.stdin.buffer.read().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out_lines=[]
    for _ in range(T):
        N=int(next(it)); M=int(next(it))
        arr1=[int(next(it)) for _ in range(N)]
        arr2=[int(next(it)) for _ in range(M)]
        i=j=0
        last=None
        res=[]
        while i<N and j<M:
            if arr1[i] < arr2[j]:
                if arr1[i]!=last:
                    res.append(arr1[i]); last=arr1[i]
                i+=1
            elif arr1[i] > arr2[j]:
                if arr2[j]!=last:
                    res.append(arr2[j]); last=arr2[j]
                j+=1
            else:
                if arr1[i]!=last:
                    res.append(arr1[i]); last=arr1[i]
                i+=1; j+=1
        while i<N:
            if arr1[i]!=last:
                res.append(arr1[i]); last=arr1[i]
            i+=1
        while j<M:
            if arr2[j]!=last:
                res.append(arr2[j]); last=arr2[j]
            j+=1
        out_lines.append(' '.join(map(str,res)))
    sys.stdout.write('\n'.join(out_lines))

if __name__=='__main__':
    solve()

